example.code:
// map: transform Ok value
let doubled = Ok::<i32, &str>(2).map(|v| v * 2);  // Ok(4)

// map_err: transform Err value
let string_err = Err::<i32, i32>(1).map_err(|e| format!("code: {e}"));

// and_then: chain fallible operations
let chained = Ok::<i32, &str>(2)
    .and_then(|v| if v > 0 { Ok(v * 2) } else { Err("negative") });

// unwrap_or: default on error
let value = Err::<i32, &str>("err").unwrap_or(0);

// unwrap_or_else: lazy default
let value = Err::<i32, &str>("err").unwrap_or_else(|_| expensive_default());

// map: transform Some value
let doubled = Some(2i32).map(|v| v * 2);  // Some(4)

// and_then: chain Options (flatMap)
let parsed = Some("42".to_string()).and_then(|s| s.parse::<i32>().ok());

// filter: conditional Some
let filtered = Some(3i32).filter(|&v| v > 5);  // None

// ok_or: Option -> Result
let result = None::<i32>.ok_or("not found");

// Result -> Option (discards error)
let opt = Ok::<i32, &str>(42).ok();

// Fail on first error
let results: Result<Vec<i32>, _> = vec!["1", "2", "3"]
    .iter()
    .map(|s| s.parse::<i32>())
    .collect();

// Best-effort: collect successes, ignore failures
let successes: Vec<i32> = vec!["1", "bad", "3"]
    .iter()
    .filter_map(|s| s.parse::<i32>().ok())
    .collect();
